CALCULATE_DEFECT_DENSITY
INPUT: total_defects, lines_of_code
OUTPUT: defect_density
BEGIN
 // Convert LOC to KLOC (thousand lines)
 KLOC = lines_of_code / 1000

 // Calculate defect density
 defect_density = total_defects / KLOC

 // Return result
 RETURN defect_density
END

// Example usage:
// total_defects = 25
// lines_of_code = 5000
// KLOC = 5
// defect_density = 25/5 = 5 defects/KLOC
